SELECT SUM(consumption_value) AS total_consumption
FROM energy_consumption
WHERE state_id = 1 AND year = 2020 AND month = 2;

SELECT consumption_value
FROM energy_consumption
WHERE consumption_id = 1;

SELECT SUM(consumption_value) AS total_energy_consumption
FROM energy_consumption
WHERE energy_source_id = 1;

SELECT MAX(total_consumption) AS highest_total_consumption
FROM yearly_consumption
WHERE state_id = 1 AND sector_id = 1 AND energy_source_id = 1;

SELECT SUM(total_consumption) AS total_energy_consumed
FROM yearly_consumption
WHERE year = 2001;

SELECT total_consumption
FROM monthly_consumption
WHERE year = 2001 AND month = 2 AND state_id = 1 AND sector_id = 0;
